import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.scaladsl.Source
import spray.json._

import scala.concurrent.Future

object WebhookProxy extends App {
  implicit val system: ActorSystem = ActorSystem()
  implicit val executionContext = system.dispatcher

  val routes = path("forward") {
    post {
      entity(as[String]) { userUrl =>
        val request = HttpRequest(uri = uri"$userUrl")
        completeWithHeaders(Http().singleRequest(request)) {
          case Success(response) =>
            Future.successful(Response(response.status, ContentTypes.`text/plain(UTF-8)`, response.entity.dataBytes))
          case Failure(exception) =>
            val errorMessage = s"Failed to forward request: ${exception.getMessage}"
            Future.successful(Response(StatusCodes.InternalServerError, ContentTypes.`text/plain(UTF-8)`, errorMessage.getBytes("UTF-8")))
        }
      }
    }
  }

  val bindingFuture = Http().bindAndHandle(routes, interface = "localhost", port = 8080)

  println(s"Server is listening on port 8080...")

  bindingFuture
    .flatMap(_.unbind()) // trigger unbinding from the current port.
    .onComplete(_ => system.terminate()) // and terminate the system.
}